SELECT upgrade.upgrade, count(*) AS change FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline ON baseline.bldg_id = upgrade.bldg_id WHERE baseline.applicability = true AND upgrade.applicability = true AND (upgrade."out.electricity.total.energy_consumption" IS NULL OR baseline."out.electricity.total.energy_consumption" IS NULL) AND (upgrade."out.natural_gas.total.energy_consumption" IS NULL OR baseline."out.natural_gas.total.energy_consumption" IS NULL) AND (upgrade."out.fuel_oil.total.energy_consumption" IS NULL OR baseline."out.fuel_oil.total.energy_consumption" IS NULL) AND (upgrade."out.propane.total.energy_consumption" IS NULL OR baseline."out.propane.total.energy_consumption" IS NULL) GROUP BY 1 ORDER BY 1